import java.io.IOException;
import java.util.ArrayList;
import java.util.List;

public class SecureCommandInjectionExample {
    public static void main(String[] args) throws IOException {
        // Safe code - user input is properly sanitized
        String userInput = "example.txt; ls";

        // Validate and sanitize user input
        if (!isValidFilename(userInput)) {
            System.out.println("Invalid filename provided.");
            return;
        }

        List<String> command = new ArrayList<>();
        command.add("cat");
        command.add(userInput);

        ProcessBuilder processBuilder = new ProcessBuilder(command);
        processBuilder.start();
    }

    private static boolean isValidFilename(String filename) {
        // Add your validation logic here (e.g., allow only certain characters or formats)
        return filename.matches("[a-zA-Z0-9\\.]+");
    }
}

